import re
def strip_cuda_comments(src: str) -> str:
    # remove // comments to end of line
    src = re.sub(r"//.*?$", "", src, flags=re.M)
    # remove /* … */ block comments (multiline)
    src = re.sub(r"/\*.*?\*/", "", src, flags=re.S)
    return src
