        res1 = rbf1(s.XYI).reshape(s.bxs, s.bxs)
        s.check("1: Constant reconstruction", np.max(np.abs(res1 - 100.0)))
        print(f"         RBF coeff norm = {np.linalg.norm(rbf1._coeffs[:s.N, 0]):.3e}")
