def test_2_linear(s):
    """Linear field v = a + b*x + c*y — exact in polynomial, detects ordering."""
    with s.test("TEST 2: Linear field  v = 10 + 0.5*x + 0.3*y"):
        _a, _b, _c = 10.0, 0.5, 0.3
        v2 = _a + _b * s.x_s + _c * s.y_s
        rbf2 = s.fit(v2)
        res2 = rbf2(s.XYI).reshape(s.bxs, s.bxs)
        truth2 = _a + _b * s.XI + _c * s.YI
        s.check("2: Linear reconstruction", np.max(np.abs(res2 - truth2)))
        print(f"         RBF coeff norm  = {np.linalg.norm(rbf2._coeffs[:s.N, 0]):.3e}")
        p2 = rbf2._coeffs[s.N:, 0]
        print(f"         Poly = {p2}")

        sh2 = np.asarray(rbf2._shift, dtype=np.float64)
        sc2 = np.atleast_1d(np.asarray(rbf2._scale, dtype=np.float64))
        S0, S1 = float(sc2[0]), float(sc2[-1])

        exp_xy = [_a + _b * sh2[0] + _c * sh2[1], _b * S0, _c * S1]
        err_xy = max(abs(p2[i] - exp_xy[i]) for i in range(3))
        exp_yx = [_a + _b * sh2[0] + _c * sh2[1], _c * S1, _b * S0]
        err_yx = max(abs(p2[i] - exp_yx[i]) for i in range(3))

        print(f"\n  Polynomial ordering detection:")
        print(f"    If [const, x, y]: expected {[f'{e:.6f}' for e in exp_xy]}, err={err_xy:.3e}")
        print(f"    If [const, y, x]: expected {[f'{e:.6f}' for e in exp_yx]}, err={err_yx:.3e}")
        if err_xy < err_yx:
            print(f"    >>> Ordering is [constant, x, y]  (matches user code)")
        elif err_yx < err_xy:
            print(f"    >>> Ordering is [constant, y, x]  (user code has x/y SWAPPED!)")
        else:
            print(f"    >>> Cannot distinguish (both errors equal)")


