def test_4_raw_vs_norm(s):
    """KEY test: raw-coord TPS basis vs normalised-coord TPS basis."""
    with s.test("TEST 4: Manual TPS reconstruction - raw vs normalised coords"):
        np.random.seed(99)
        v4 = np.random.randn(s.N) * 30 + 500
        rbf4 = s.fit(v4)
        ref4 = rbf4(s.XYI).reshape(s.bxs, s.bxs)
        c4  = rbf4._coeffs
        sh4 = np.asarray(rbf4._shift, dtype=np.float64)
        sc4 = np.atleast_1d(np.asarray(rbf4._scale, dtype=np.float64))

        obs    = np.column_stack([s.x_s, s.y_s])
        grid   = s.XYI.copy()
        obs_n  = (obs  - sh4) / sc4
        grid_n = (grid - sh4) / sc4

        def build_tps_matrix(eval_pts, src_pts):
            diff = eval_pts[:, None, :] - src_pts[None, :, :]
            r2 = np.sum(diff ** 2, axis=2)
            return np.where(r2 > 0, 0.5 * r2 * np.log(r2), 0.0)

        P_n = np.column_stack([np.ones(len(grid)), grid_n])

        K_raw = build_tps_matrix(grid, obs)
        man_raw = (K_raw @ c4[:s.N] + P_n @ c4[s.N:]).reshape(s.bxs, s.bxs)
        err_raw = np.max(np.abs(man_raw - ref4))
        s.check("4a: Raw-coord TPS + norm poly", err_raw)

        K_norm = build_tps_matrix(grid_n, obs_n)
        man_norm = (K_norm @ c4[:s.N] + P_n @ c4[s.N:]).reshape(s.bxs, s.bxs)
        err_norm = np.max(np.abs(man_norm - ref4))
        s.check("4b: Norm-coord TPS + norm poly", err_norm)

        print(f"\n  Comparison:")
        print(f"    Raw-coord error:  {err_raw:.3e}")
        print(f"    Norm-coord error: {err_norm:.3e}")
        if err_norm < err_raw:
            ratio = err_raw / max(err_norm, 1e-300)
            print(f"    >>> NORMALISED wins ({ratio:.1f}x better)")
        elif err_raw < err_norm:
            ratio = err_norm / max(err_raw, 1e-300)
            print(f"    >>> RAW wins ({ratio:.1f}x better)")
        else:
            print(f"    >>> Both identical")


def test_5_custom_rbf_eval(s):
    """Replicate custom_rbf_eval's pixel loop in pure Python, raw vs normalised."""
    with s.test("TEST 5: Replicate custom_rbf_eval loop (pure Python)"):
        np.random.seed(55)
        v5 = np.random.randn(s.N) * 20 + 300
        rbf5 = s.fit(v5)
        ref5 = rbf5(s.XYI).reshape(s.bxs, s.bxs)
        c5  = rbf5._coeffs
        sh5 = np.asarray(rbf5._shift, dtype=np.float64)
        sc5 = np.atleast_1d(np.asarray(rbf5._scale, dtype=np.float64))

        dxy = np.zeros((4, s.N), dtype=np.float64)

        # 5a: Raw coords
        man5_raw = np.zeros((s.bxs, s.bxs), dtype=np.float64)
        for idy in range(s.bxs):
            for idx in range(s.bxs):
                dxy[0] = s.XI[idy, idx] - s.x_s
                dxy[1] = s.YI[idy, idx] - s.y_s
                dxy[2] = dxy[0]**2 + dxy[1]**2
                with np.errstate(divide='ignore', invalid='ignore'):
                    dxy[3] = dxy[2] * np.log(dxy[2]) / 2.0
                dxy[3][dxy[2] == 0] = 0
                man5_raw[idy, idx] = np.sum(dxy[3] * c5[:s.N, 0])
        man5_raw += c5[-3, 0] + c5[-2, 0]*(s.XI - sh5[0])/sc5[0] + c5[-1, 0]*(s.YI - sh5[1])/sc5[-1]
        s.check("5a: custom_rbf_eval (raw coords)", np.max(np.abs(man5_raw - ref5)))

        # 5b: Normalised coords
        man5_norm = np.zeros((s.bxs, s.bxs), dtype=np.float64)
        for idy in range(s.bxs):
            for idx in range(s.bxs):
                dxy[0] = (s.XI[idy, idx] - s.x_s) / sc5[0]
                dxy[1] = (s.YI[idy, idx] - s.y_s) / sc5[-1]
                dxy[2] = dxy[0]**2 + dxy[1]**2
                with np.errstate(divide='ignore', invalid='ignore'):
                    dxy[3] = dxy[2] * np.log(dxy[2]) / 2.0
                dxy[3][dxy[2] == 0] = 0
                man5_norm[idy, idx] = np.sum(dxy[3] * c5[:s.N, 0])
        man5_norm += c5[-3, 0] + c5[-2, 0]*(s.XI - sh5[0])/sc5[0] + c5[-1, 0]*(s.YI - sh5[1])/sc5[-1]
        s.check("5b: custom_rbf_eval (normalised coords)", np.max(np.abs(man5_norm - ref5)))

        print(f"\n  >>> {'NORMALISED' if np.max(np.abs(man5_norm - ref5)) < np.max(np.abs(man5_raw - ref5)) else 'RAW'} matches scipy")


