def test_7_old_rbf_manual(s):
    """Manually reconstruct old Rbf's output using its normalised [0,1] coordinates."""
    from scipy.interpolate import Rbf
    with s.test("TEST 7: Old Rbf internal reconstruction"):
        np.random.seed(77)
        v7 = np.random.randn(s.N) * 30 + 500
        try:
            rbf7 = Rbf(s.x_s, s.y_s, v7, function='thin-plate', smooth=0.0)
            ref7 = rbf7(s.XI, s.YI)
            print(f"  Old Rbf attributes:")
            print(f"    nodes.shape = {rbf7.nodes.shape}")
            print(f"    xi.shape    = {rbf7.xi.shape}")
            print(f"    xi min/max  = {rbf7.xi.min():.4f} / {rbf7.xi.max():.4f}")

            x_old_norm = (s.XI - s.x_s.min()) / (s.x_s.max() - s.x_s.min())
            y_old_norm = (s.YI - s.y_s.min()) / (s.y_s.max() - s.y_s.min())

            man7 = np.zeros((s.bxs, s.bxs), dtype=np.float64)
            for idy in range(s.bxs):
                for idx in range(s.bxs):
                    for n in range(s.N):
                        dx = x_old_norm[idy, idx] - rbf7.xi[0, n]
                        dy = y_old_norm[idy, idx] - rbf7.xi[1, n]
                        r2 = dx*dx + dy*dy
                        if r2 > 0:
                            man7[idy, idx] += rbf7.nodes[n] * r2 * np.log(np.sqrt(r2))

            s.check("7: Old Rbf manual reconstruction", np.max(np.abs(man7 - ref7)))
            print(f"         (Old Rbf uses normalised [0,1] coords for kernel)")
            print(f"         Old vs New surface diff: {np.max(np.abs(ref7 - s.fit(v7)(s.XYI).reshape(s.bxs, s.bxs))):.3e}")
            print(f"         This is expected: TPS is scale-dependent.")
        except Exception as e:
            print(f"  [SKIP] Old Rbf errored: {e}")


