def test_9_f32_truncation(s):
    """Simulate f32 storage truncation — predicts CUDA error floor."""
    with s.test("TEST 9: f32 truncation simulation (predicts CUDA error floor)"):
        d = getattr(s, '_test8', None)
        if d is None:
            print("  [SKIP] Run test_8 first to populate data")
            return

        XYI8, xs8, ys8, N8 = d['XYI8'], d['xs8'], d['ys8'], d['N8']
        ref8, c8, sh8, sc8, bxs8 = d['ref8'], d['c8'], d['sh8'], d['sc8'], d['bxs8']

        xs_f32 = xs8.astype(np.float32).astype(np.float64)
        ys_f32 = ys8.astype(np.float32).astype(np.float64)
        c_f32  = c8[:N8, 0].astype(np.float32).astype(np.float64)
        sh_f32 = sh8.astype(np.float32).astype(np.float64)
        sc_f32 = sc8.astype(np.float32).astype(np.float64)
        lin_f32 = c8[N8:, 0].astype(np.float32).astype(np.float64)

        obs_f32 = np.column_stack([xs_f32, ys_f32])
        diff9 = XYI8[:, None, :] - obs_f32[None, :, :]
        r2_9 = np.sum(diff9**2, axis=2)
        K9 = np.where(r2_9 > 0, 0.5 * r2_9 * np.log(r2_9), 0.0)
        grid9_n = (XYI8 - sh_f32) / sc_f32
        P9 = np.column_stack([np.ones(len(XYI8)), grid9_n])
        man9 = (K9 @ c_f32[:, None] + P9 @ lin_f32[:, None]).reshape(bxs8, bxs8)

        err9_abs = np.max(np.abs(man9 - ref8))
        err9_rel = np.max(np.abs((man9 - ref8) / ref8))
        s.check("9: f32 truncation (abs)", err9_abs, tol=1.0)
        print(f"         max|relative err| = {err9_rel:.3e}")
        print(f"         (This predicts the CUDA-vs-scipy error floor)")


