def test_11_kernel_formula(s):
    """Compare r^2*log(r^2)/2 vs scipy's exact r^2*log(r)."""
    with s.test("TEST 11: Exact scipy kernel formula r^2*log(r) vs r^2*log(r^2)/2"):
        np.random.seed(111)
        v11 = np.random.randn(s.N) * 25 + 400
        rbf11 = s.fit(v11)
        ref11 = rbf11(s.XYI).reshape(s.bxs, s.bxs)
        c11  = rbf11._coeffs
        sh11 = np.asarray(rbf11._shift, dtype=np.float64)
        sc11 = np.atleast_1d(np.asarray(rbf11._scale, dtype=np.float64))

        obs11 = np.column_stack([s.x_s, s.y_s])
        diff11 = s.XYI[:, None, :] - obs11[None, :, :]
        r2_11 = np.sum(diff11**2, axis=2)

        K_ours = np.where(r2_11 > 0, 0.5 * r2_11 * np.log(r2_11), 0.0)
        r_11 = np.sqrt(r2_11)
        K_scipy = np.where(r_11 > 0, r_11**2 * np.log(r_11), 0.0)

        grid11_n = (s.XYI - sh11) / sc11
        P11 = np.column_stack([np.ones(len(s.XYI)), grid11_n])

        man_ours  = (K_ours  @ c11[:s.N] + P11 @ c11[s.N:]).reshape(s.bxs, s.bxs)
        man_scipy = (K_scipy @ c11[:s.N] + P11 @ c11[s.N:]).reshape(s.bxs, s.bxs)

        s.check("11a: r^2*log(r^2)/2 vs scipy", np.max(np.abs(man_ours  - ref11)))
        s.check("11b: r^2*log(r) vs scipy",     np.max(np.abs(man_scipy - ref11)))
        print(f"         Formula difference: {np.max(np.abs(man_ours - man_scipy)):.3e}")
        print(f"         Both correct, ~1e-12 from matmul vs loop ordering")


def test_12_scipy_internals(s):
    """Bit-exact: call scipy's own _build_evaluation_coefficients."""
    with s.test("TEST 12: Bit-exact via scipy internals"):
        try:
            from scipy.interpolate._rbfinterp_pythran import _build_evaluation_coefficients
        except ImportError:
            try:
                from scipy.interpolate._rbfinterp import _build_evaluation_coefficients
            except ImportError:
                print("  [SKIP] Could not import _build_evaluation_coefficients")
                return

        np.random.seed(222)
        v12 = np.random.randn(s.N) * 30 + 500
        rbf12 = s.fit(v12)
        ref12 = rbf12(s.XYI).reshape(s.bxs, s.bxs)

        vec12 = _build_evaluation_coefficients(
            s.XYI.astype(np.float64),
            np.column_stack([s.x_s, s.y_s]),
            'thin_plate_spline', 1.0,
            rbf12.powers, rbf12._shift, rbf12._scale,
        )
        man12 = np.dot(vec12, rbf12._coeffs).reshape(s.bxs, s.bxs)
        s.check("12: Bit-exact via _build_eval_coeffs", np.max(np.abs(man12 - ref12)), tol=1e-15)


def test_13_manual_replica(s):
    """Pure-python scalar-loop replica of the pythran source — the CUDA reference."""
    with s.test("TEST 13: Manual exact replica of scipy internals"):
        np.random.seed(333)
        v13 = np.random.randn(s.N) * 40 + 700
        rbf13 = s.fit(v13)
        ref13 = rbf13(s.XYI).reshape(s.bxs, s.bxs)
        c13    = rbf13._coeffs
        obs13  = np.column_stack([s.x_s, s.y_s])
        powers = rbf13.powers

        M = len(s.XYI)
        vec13 = np.empty((M, s.N + 3), dtype=np.float64)
        for i in range(M):
            for j in range(s.N):
                r = np.linalg.norm(s.XYI[i] - obs13[j])
                vec13[i, j] = r**2 * np.log(r) if r != 0 else 0.0
        xhat13 = (s.XYI - rbf13._shift) / rbf13._scale
        for i in range(M):
            for k in range(powers.shape[0]):
                vec13[i, s.N + k] = np.prod(xhat13[i] ** powers[k])

        man13 = np.dot(vec13, c13).reshape(s.bxs, s.bxs)
        s.check("13: Pure-python exact replica", np.max(np.abs(man13 - ref13)), tol=1e-14)
        print(f"         powers = {powers.tolist()}")
        print(f"         This is the formula to port to CUDA")


def test_14_numba_replica(s):
    """Numba-compiled replica of _build_evaluation_coefficients."""
    with s.test("TEST 14: Numba replica of _build_evaluation_coefficients"):
        np.random.seed(222)
        v14 = np.random.randn(s.N) * 30 + 500
        rbf14 = s.fit(v14)
        ref14 = rbf14(s.XYI).reshape(s.bxs, s.bxs)

        vec14 = custom_build_evaluation_coefficients(
            s.XYI.astype(np.float64),
            np.column_stack([s.x_s, s.y_s]),
            1.0,
            rbf14.powers,
            rbf14._shift,
            rbf14._scale,
        )
        man14 = np.dot(vec14, rbf14._coeffs).reshape(s.bxs, s.bxs)
        s.check("14: Numba _build_eval_coeffs", np.max(np.abs(man14 - ref14)), tol=1e-15)


